SELECT DISTINCT "Category" 
FROM "Product"
ORDER BY "Category" ASC;

SELECT DISTINCT "Color" AS "Color"
FROM "Product"
ORDER BY "Color" ASC;

SELECT DISTINCT "Sales_Territory"."Region" AS "Region", "Sales_Territory"."Country" AS "Country"
FROM "Sales_Territory"
ORDER BY "Sales_Territory"."Region" ASC;

SELECT DISTINCT "Fiscal Year" AS "Fiscal Year"
FROM "Date"
ORDER BY "Fiscal Year" ASC;

SELECT DISTINCT "Channel" 
FROM "Sales_Order"
ORDER BY "Channel" ASC;

SELECT DISTINCT "Country-Region"
FROM "Customer"
ORDER BY "Country-Region" ASC;

SELECT DISTINCT "Business Type" AS "Business Type"
FROM "Reseller"
ORDER BY "Business Type" ASC;

SELECT DISTINCT "Fiscal Quarter" AS "Fiscal Quarter"
FROM "Date"
ORDER BY "Fiscal Quarter" ASC;
